const r = $input.first().json.report || {};
const term = r.term;
const projects = r.projects || [];
const clients = r.clients || [];
const events = r.recent_events || [];
const row = (cells) => '<tr>'+cells.map(c=>'<td style="padding:6px 8px;border-bottom:1px solid #eee;font-size:12px">'+c+'</td>').join('')+'</tr>';
const section = (title, body, count) => '<h2 style="color:#374151;font-size:15px;margin:20px 0 8px">'+title+(count!==undefined?' <span style="color:#6b7280">('+count+')</span>':'')+'</h2>'+body;
const tbl = (headers, rows) => '<table style="width:100%;background:white;border-collapse:collapse;border-radius:6px;overflow:hidden"><thead style="background:#1f2937;color:white"><tr>'+headers.map(h=>'<th style="padding:8px;text-align:left;font-size:11px">'+h+'</th>').join('')+'</tr></thead><tbody>'+(rows.length>0?rows.join(''):row(headers.map(()=>'<i style="color:#6b7280">sin resultados</i>')))+'</tbody></table>';
const projRows = projects.map(p=>row([
  '<a href="/webhook/admin-project?project_id='+p.id+'" style="color:#2563eb;font-weight:600;text-decoration:none">'+p.name+'</a>',
  '<code>'+p.current_phase+'</code>',
  p.project_type||'-',
  p.location_city||'-',
  '<code>'+p.status+'</code>',
  new Date(p.updated_at).toISOString().slice(0,10)
]));
const clientRows = clients.map(c=>row([
  '<b>'+c.name+'</b>',
  '<code>'+(c.email||'-')+'</code>',
  new Date(c.created_at).toISOString().slice(0,10)
]));
const eventRows = events.map(e=>row([
  e.event_type, e.severity, e.source_ip||'-',
  new Date(e.occurred_at).toISOString().slice(0,16).replace('T',' '),
  e.preview||'-'
]));
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Buscar — ArquitAI</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:1100px;margin:24px auto;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0 0 4px}form{background:white;padding:14px;border-radius:8px;margin:16px 0;display:flex;gap:8px}input[type=text]{flex:1;padding:8px 12px;border:1px solid #d1d5db;border-radius:4px;font-size:14px}button{padding:8px 16px;background:#2563eb;color:white;border:0;border-radius:4px;cursor:pointer;font-size:14px}.meta{color:#64748b;font-size:13px}</style>' +
'</head><body>' +
'<a href="/webhook/admin-index" style="color:#2563eb;font-size:13px;text-decoration:none">← Admin index</a>' +
'<h1>Buscar</h1>' +
'<form method="get" action="/webhook/admin-search"><input type="text" name="q" placeholder="nombre proyecto, ciudad, email cliente o IP..." value="'+(term||'')+'" autofocus><button type="submit">Buscar</button></form>' +
(term ? ('<div class="meta">Resultados para <b>'+term+'</b></div>' +
  section('Proyectos', tbl(['Proyecto','Fase','Tipo','Ciudad','Status','Update'], projRows), projects.length) +
  section('Clientes', tbl(['Nombre','Email','Creado'], clientRows), clients.length) +
  section('Security events relacionados', tbl(['Tipo','Sev','IP','Cuando','Preview'], eventRows), events.length))
: '<div class="meta">Introduce un termino para buscar.</div>') +
'</body></html>';
return [{ json: { html } }];
